
const name = "number",
	description = `number|nb,[paramÃĻtres]

**paramÃĻtres**
- [1,2,3,4,...]: nombre de chiffres aprÃĻs la virgule
- s: significatif (donc 2.3 ne passe pas pour 2.30)
`

export function NumberChecker(options){
	options = options ?? []

	// TODO: ajouter le significatif
	return {
		name, description,
		format: () => {
			if (isNaN(options[0])) {
				return "rÃĐponse numÃĐrique"
			} else {
				return `rÃĐponse avec ${options[0]} chiffre(s) aprÃĻs la virgule`
			}
		},
		check: (expectedAnswer, answer = []) => {
			// Le rÃĐsultat est exactement ce qui est demandÃĐ
			if (answer.toString() === expectedAnswer.toString()) {
				return {
					result: true,
					message: ""
				}
			}

			// Il n'y a pas d'option -> le rÃĐsultat ne peut pas ÃŠtre validÃĐ.
			if (options.length === 0) {
				return {
					result: false,
					message: "ce n'est pas la bonne rÃĐponse"
				}
			}

			// Nombre de dÃĐcimales souhaitÃĐes
			const nbDecimales = +options[0]
			// Nomber de dÃĐcimale de la rÃĐponse
			let crtDecimales = answer.toString().split(".")

			// Le nombre de chiffres aprÃĻs la virgule n'est pas juste
			if (crtDecimales.length === 1 || crtDecimales[1].length !== nbDecimales) {
				return {
					result: false,
					message: `Il faut ${nbDecimales} chiffre(s) aprÃĻs la virgule.`
				}
			}
			crtDecimales = crtDecimales[1]

			// Le dernier chiffre n'est pas juste - il s'agit peut ÃŠtre d'un problÃĻme d'arrondi ?
			if (crtDecimales[crtDecimales.length - 1] - expectedAnswer.toString()[expectedAnswer.toString().length - 1] === 1) {
				return {
					result: false,
					message: "Peut ÃŠtre un problÃĻme d'arrondi ?"
				}
			}

			return {
				result: false,
				message: ""
			}
		}
	}

}
