import {NumExp} from "pimath/esm/maths/numexp"

const name = "log"
const description = `log,[paramÃĻtres]

**paramÃĻtres**
`
export function LogChecker(options) {
	options = options ?? []

	return {
		name, description,
		format: () => {
			return "rÃĐponse sous forme exacte, rÃĐduite"
		},
		check: (expectedAnswer, answer = []) => {
			// Le rÃĐsultat est exactement ce qui est demandÃĐ
			const stringAnswer = answer.toString(),
				asciiAnswer = stringAnswer.startsWith("#") ? stringAnswer.substring(1) : stringAnswer

			if (asciiAnswer === expectedAnswer.toString()) {
				return {
					result: true,
					message: ""
				}
			}

			// Il ne peut pas y avoir de point.
			if(asciiAnswer.includes(".")){
				return{
					result: false,
					message: "La rÃĐponse n'est pas sous forme exact (nombres entiers)"
				}
			}

			// Il ne doit y avoir qu'une fraction.
			let ND = asciiAnswer.split("/")
			if(ND.length>2){
				// TODO: on devrait autoriser les fractions dans le log - ne pas les compter si c'est entre deux parenthÃĻses...

				return {
					result: false,
					message: "La rÃĐponse ne peut contenir qu'une seule barre de fraction."
				}
			}

			let userN, userD, expN, expD
			try{
				userN = new NumExp(ND[0]).evaluate()
			}catch{
				return {
					result: false,
					message: `${ND.length===1?"La rÃĐponse":"Le numÃĐrateur"} n'est pas correctement formÃĐ.`
				}
			}

			if(ND.length===2) {
				try {
					userD = new NumExp(ND[1]).evaluate()
				} catch {
					return {
						result: false,
						message: "Le dÃĐnominateur n'est pas correctement formÃĐ."
					}
				}
			}else{
				ND = 1
			}

			[expN, expD] = expectedAnswer.split("/")
			try{
				expN = new NumExp(expN).evaluate()
			}catch{}
			if(expD===undefined){expD = 1}else{
				try{
					expD = new NumExp(expD).evaluate()
				}catch{}
			}


			let answerDecimal = userN/userD,
				expectedDecimal = expN / expD

			if(answerDecimal.toFixed(8) !== expectedDecimal.toFixed(8)){
				return {
					result: false,
					message: "La rÃĐpnse sous forme exacte ne donne pas la bonne valeur."
				}
			}

			return {
				result: true,
				message: ""
			}
		}
	}
}
