import {PiMath} from "pimath/esm"

const name="fraction"

const description = `fraction,[paramÃĻtres]

**paramÃĻtres**
- r=rÃĐduit
`
export function FractionChecker(options){
	options = options??[]

	const expectReduced = options.includes("r") || options.includes("reduced")

	return {name, description,
		format: () => {
			let opts = []
			if (expectReduced) {
				opts.push("rÃĐduite")
			}

			return `rÃĐponse sous forme de fraction ${opts.join(",")}`
		},
		check: (expectedAnswer, answer = []) => {
			// Le rÃĐsultat est exactement ce qui est demandÃĐ
			if(answer===expectedAnswer){
				return {
					result: true,
					message: ""
				}
			}

			let FAnswer, FExpected

			try{
				FAnswer = new PiMath.Fraction(answer)
				FExpected = new PiMath.Fraction(expectedAnswer)
			}catch{
				return {
					result: false,
					message: "La fraction n'est pas formatÃĐe correctement."
				}
			}

			if(FAnswer.isNotEqual(FExpected)){
				return {
					result: false,
					message: "La rÃĐponse donnÃĐe n'est pas juste."
				}
			}

			if(FAnswer.denominator<0){
				return {
					result: false,
					message: "Le dÃĐnominateur doit ÃŠtre positif."
				}
			}

			if(!FAnswer.isReduced() && expectReduced){
				return {
					result: false,
					message: "La fraction n'est pas rÃĐduite."
				}
			}


			return {
				result: true,
				message: ""
			}
		}
	}

}
